CREATE TABLE IF NOT EXISTS teams (id UUID PRIMARY KEY, name TEXT NOT NULL, created_at TIMESTAMPTZ DEFAULT now(), updated_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE IF NOT EXISTS users (id UUID PRIMARY KEY, team_id UUID REFERENCES teams(id), email TEXT UNIQUE NOT NULL, role TEXT NOT NULL, created_at TIMESTAMPTZ DEFAULT now(), updated_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE IF NOT EXISTS channels (id UUID PRIMARY KEY, team_id UUID REFERENCES teams(id), name TEXT NOT NULL, created_at TIMESTAMPTZ DEFAULT now(), updated_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE IF NOT EXISTS channel_profiles (id UUID PRIMARY KEY, channel_id UUID REFERENCES channels(id), profile JSONB NOT NULL, created_at TIMESTAMPTZ DEFAULT now(), updated_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE IF NOT EXISTS assets (id UUID PRIMARY KEY, channel_id UUID REFERENCES channels(id), filename TEXT NOT NULL, duration_seconds NUMERIC, status TEXT NOT NULL, metadata JSONB DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ DEFAULT now(), updated_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE IF NOT EXISTS projects (id UUID PRIMARY KEY, channel_id UUID REFERENCES channels(id), asset_id UUID REFERENCES assets(id), status TEXT NOT NULL, priority NUMERIC DEFAULT 0, created_at TIMESTAMPTZ DEFAULT now(), updated_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE IF NOT EXISTS strategies (id UUID PRIMARY KEY, project_id UUID REFERENCES projects(id), strategy_number INT NOT NULL, payload JSONB NOT NULL, overall_score NUMERIC DEFAULT 0, created_at TIMESTAMPTZ DEFAULT now(), updated_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE IF NOT EXISTS tasks (id UUID PRIMARY KEY, project_id UUID REFERENCES projects(id), task_type TEXT NOT NULL, status TEXT NOT NULL, payload JSONB DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ DEFAULT now(), updated_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE IF NOT EXISTS upload_queue (id UUID PRIMARY KEY, project_id UUID REFERENCES projects(id), strategy_id UUID REFERENCES strategies(id), scheduled_time TIMESTAMPTZ, upload_status TEXT NOT NULL, selected_title TEXT, selected_hook TEXT, selected_thumbnail_copy TEXT, created_at TIMESTAMPTZ DEFAULT now(), updated_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE IF NOT EXISTS performance_records (id UUID PRIMARY KEY, project_id UUID REFERENCES projects(id), strategy_id UUID REFERENCES strategies(id), upload_date DATE, views BIGINT, likes BIGINT, comments BIGINT, title_used TEXT, hook_used TEXT, thumbnail_copy_used TEXT, notes TEXT, created_at TIMESTAMPTZ DEFAULT now(), updated_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE IF NOT EXISTS recommendation_snapshots (id UUID PRIMARY KEY, channel_id UUID REFERENCES channels(id), snapshot JSONB NOT NULL, created_at TIMESTAMPTZ DEFAULT now(), updated_at TIMESTAMPTZ DEFAULT now());
